/**
 * Get the greatest numerical value + 1 of all the enumerated values of the LINK set of enumerated values.
 *
 * \param[in] UNIT  is the index of the STRSWITCH unit relative to the set of enumerated values that must be considered;
 *                  possible values for \e UNIT are:
 *                  - UNIT == 0: STRSWITCH_0
 * \return the greatest numerical value + 1 of all the enumerated values of the LINK set of enumerated values and associated with STRSWITCH unit having index \e UNIT
 */

#define ATON_STRSWITCH_LINK_NUM(UNIT) \
  (((UNIT) < 1) ? UINT8_C(11) : 0))


/** Source port: Output port of Stream Engine 0 (STRSWITCH_0 unit). */
#define ATON_STRSWITCH_0_LINK_STRENG_0_0 UINT8_C(0x0)

/** Source port: Output port of Stream Engine 1 (STRSWITCH_0 unit). */
#define ATON_STRSWITCH_0_LINK_STRENG_1_0 UINT8_C(0x1)

/** Source port: Output port of Stream Engine 2 (STRSWITCH_0 unit). */
#define ATON_STRSWITCH_0_LINK_STRENG_2_0 UINT8_C(0x2)

/** Source port: Output port of Stream Engine 3 (STRSWITCH_0 unit). */
#define ATON_STRSWITCH_0_LINK_STRENG_3_0 UINT8_C(0x3)

/** Source port: Output port of Stream Engine 4 (STRSWITCH_0 unit). */
#define ATON_STRSWITCH_0_LINK_STRENG_4_0 UINT8_C(0x4)

/** Source port: Output port of Stream Engine 5 (STRSWITCH_0 unit). */
#define ATON_STRSWITCH_0_LINK_STRENG_5_0 UINT8_C(0x5)

/** Source port: Output port of Convolutional Accelerator 0 (STRSWITCH_0 unit). */
#define ATON_STRSWITCH_0_LINK_CONVACC_0_0 UINT8_C(0x6)

/** Source port: Output port of Activation Accelerator 0 (STRSWITCH_0 unit). */
#define ATON_STRSWITCH_0_LINK_ACTIV_0_0 UINT8_C(0x7)

/** Source port: Output port of Arithmetic Accelerator 0 (STRSWITCH_0 unit). */
#define ATON_STRSWITCH_0_LINK_ARITH_0_0 UINT8_C(0x8)

/** Source port: Output port of Arithmetic Accelerator 1 (STRSWITCH_0 unit). */
#define ATON_STRSWITCH_0_LINK_ARITH_1_0 UINT8_C(0x9)

/** Source port: Output port of Pooling Accelerator 0 (STRSWITCH_0 unit). */
#define ATON_STRSWITCH_0_LINK_POOL_0_0 UINT8_C(0xa)


/**
 * Check if a numerical value is a valid numerical value of the LINK set of enumerated values.
 *
 * \param[in] UNIT  is the index of the STRSWITCH unit relative to the numerical value that must be checked;
 *                  possible values for \e UNIT are:
 *                  - UNIT == 0: STRSWITCH_0
 * \param[in] VALUE is the numerical value that must be checked
 *
 * \retval \e true  if \e value is a valid numerical value of the LINK set of enumerated values (associated with STRSWITCH unit having index \e UNIT)
 * \retval \e false otherwise
 */

#define ATON_STRSWITCH_LINK_IS_VALID(UNIT, VALUE) \
  (((VALUE) == UINT8_C(0)) ? true : \
   ((VALUE) == UINT8_C(1)) ? true : \
   ((VALUE) == UINT8_C(2)) ? true : \
   ((VALUE) == UINT8_C(3)) ? true : \
   ((VALUE) == UINT8_C(4)) ? true : \
   ((VALUE) == UINT8_C(5)) ? true : \
   ((VALUE) == UINT8_C(6)) ? true : \
   ((VALUE) == UINT8_C(7)) ? true : \
   ((VALUE) == UINT8_C(8)) ? true : \
   ((VALUE) == UINT8_C(9)) ? true : \
   ((VALUE) == UINT8_C(10)) ? true : false)


/**
 * Get the symbolic name of one of the numerical values of the LINK set of enumerated values.
 *
 * \param[in] UNIT  is the index of the STRSWITCH unit relative to the enumerated value whose identifier must be returned;
 *                  possible values for \e UNIT are:
 *                  - UNIT == 0: STRSWITCH_0
 * \param[in] VALUE is the numerical value whose identifier must be returned
 *
 * \return the symbolic name of enumerated value having numerical value equal to \e VALUE and associated with STRSWITCH unit having index \e UNIT
 */

#define ATON_STRSWITCH_LINK_ID(UNIT, VALUE) \
  ((const volatile uint8_t *)(((VALUE) == UINT8_C(0)) ? "STRENG_0_0" : \
                     ((VALUE) == UINT8_C(1)) ? "STRENG_1_0" : \
                     ((VALUE) == UINT8_C(2)) ? "STRENG_2_0" : \
                     ((VALUE) == UINT8_C(3)) ? "STRENG_3_0" : \
                     ((VALUE) == UINT8_C(4)) ? "STRENG_4_0" : \
                     ((VALUE) == UINT8_C(5)) ? "STRENG_5_0" : \
                     ((VALUE) == UINT8_C(6)) ? "CONVACC_0_0" : \
                     ((VALUE) == UINT8_C(7)) ? "ACTIV_0_0" : \
                     ((VALUE) == UINT8_C(8)) ? "ARITH_0_0" : \
                     ((VALUE) == UINT8_C(9)) ? "ARITH_1_0" : \
                     ((VALUE) == UINT8_C(10)) ? "POOL_0_0" : ""))


/**
 * Get the description of one of the numerical values of the LINK set of enumerated values.
 *
 * \param[in] UNIT  is the index of the STRSWITCH unit relative to the enumerated value whose description must be returned;
 *                  possible values for \e UNIT are:
 *                  - UNIT == 0: STRSWITCH_0
 * \param[in] VALUE is the numerical value whose description must be returned
 *
 * \return the description of enumerated value having numerical value equal to \e VALUE and associated with UNIT unit having index \e STRSWITCH
 */

#define ATON_STRSWITCH_LINK_DESC(UNIT, VALUE) \
  ((const volatile uint8_t *)(((VALUE) == UINT8_C(0)) ? "Output port of Stream Engine 0" : \
                     ((VALUE) == UINT8_C(1)) ? "Output port of Stream Engine 1" : \
                     ((VALUE) == UINT8_C(2)) ? "Output port of Stream Engine 2" : \
                     ((VALUE) == UINT8_C(3)) ? "Output port of Stream Engine 3" : \
                     ((VALUE) == UINT8_C(4)) ? "Output port of Stream Engine 4" : \
                     ((VALUE) == UINT8_C(5)) ? "Output port of Stream Engine 5" : \
                     ((VALUE) == UINT8_C(6)) ? "Output port of Convolutional Accelerator 0" : \
                     ((VALUE) == UINT8_C(7)) ? "Output port of Activation Accelerator 0" : \
                     ((VALUE) == UINT8_C(8)) ? "Output port of Arithmetic Accelerator 0" : \
                     ((VALUE) == UINT8_C(9)) ? "Output port of Arithmetic Accelerator 1" : \
                     ((VALUE) == UINT8_C(10)) ? "Output port of Pooling Accelerator 0" : ""))


