/**
 * Get the mask for retrieving the value of a field of a 32-bit register.
 *
 * \param[in] OFFSET is the offset of the field in the register
 * \param[in] SIZE   is the size in bits of the register
 *
 * \return the mask of the field having \e OFFSET offset and \e SIZE size
 */

#define ATON_FIELD_MASK32(OFFSET, SIZE) \
  ((uint32_t)(((UINT64_C(1) << (SIZE)) - 1) << (OFFSET)))


/**
 * Get the value of a field of a 32-bit register.
 *
 * \param[in] REG    is the value of the register containing the field whose value that must be retrieved
 * \param[in] OFFSET is the offset of the field in the register
 * \param[in] SIZE   is the size in bits of the register
 *
 * \return the value of the field contained in \e REG register and having \e OFFSET offset and \e SIZE size
 */

#define ATON_GET_FIELD32(REG, OFFSET, SIZE) \
  (((REG) & ATON_FIELD_MASK32((OFFSET), (SIZE))) >> (OFFSET))


/**
 * Set the value of a field of a register.
 *
 * \param[in] REG    is the current value of the register containing the field whose value that must be retrieved
 * \param[in] OFFSET is the offset of the field in the register
 * \param[in] SIZE   is the size in bits of the register
 * \param[in] DATA   is the new value that must be set for the field
 *
 * \return the new value of the register after modifying the field having \e OFFSET offset and \e SIZE size with \e DATA value
 */

#define ATON_SET_FIELD32(REG, OFFSET, SIZE, DATA) \
  (((REG) & (~ATON_FIELD_MASK32((OFFSET), (SIZE)))) | (((DATA) << (OFFSET)) & ATON_FIELD_MASK32((OFFSET), (SIZE))))


#ifndef ATON_HIDE_REG_MACROS

/**
 * Read the value of a 32-bit register.
 *
 * \param[in] ADDR is the address of the register that must be read
 *
 * \return the value of the register having address \e ADDR
 */

#define ATON_GET_REG32(ADDR) \
  (*((volatile uint32_t *)(uintptr_t)(ADDR)))


/**
 * Write the value of a 32-bit register.
 *
 * \param[in] ADDR is the address of the register that must be modified
 * \param[in] DATA is the value that must be written to the register
 */

#define ATON_SET_REG32(ADDR, DATA) \
  do { *((volatile uint32_t *)(uintptr_t)(ADDR)) = (DATA); } while (0)


#endif    // #ifndef ATON_HIDE_REG_MACROS


#ifdef ATON_RO_ERROR_FUNCTION

/**
 * Print an error because there is an attempt to modify a read-only register or field.
 *
 * \param[in] desc is the description of the read-only register or field involved in this attempt
 *
 * \return 0
 */

static inline uint32_t ATON_RO_ERROR(const uint8_t *desc)
{
  fprintf(stderr, "Error: Trying to write the value of %s\n\n", desc);

  return 0;
}

#else    // #ifdef ATON_RO_ERROR_FUNCTION


/** Do nothing. */
static inline uint32_t ATON_RO_ERROR(const uint8_t *desc) { return 0; }

#endif    // #ifdef ATON_RO_ERROR_FUNCTION


