/* **************************************************************************** CTRL register of one of the ACTIV units ***************************************************************************** */

/** Offset of the ACTIV.CTRL register from the base address of the ACTIV unit. */
#define ATON_ACTIV_CTRL_OFFSET  UINT32_C(0x0)

/**
 * Get the address of the ACTIV.CTRL register of the ACTIV unit.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'ACTIV_0'
 *
 * \return the address of the ACTIV.CTRL register of ACTIV unit template
 */

#define ATON_ACTIV_CTRL_ADDR(UNIT) \
  (ATON_ACTIV_BASE(UNIT) + ATON_ACTIV_CTRL_OFFSET)


/** Reset value of the ACTIV.CTRL register of the ACTIV unit. */
#define ATON_ACTIV_CTRL_DT  UINT32_C(0x00881080)


/** Read-write access rights mask of the ACTIV.CTRL register of the ACTIV unit. */
#define ATON_ACTIV_CTRL_RW  UINT32_C(0x43ffffdf)

