/**
 * Get the offset of one of the ARITH.COEFF_AB registers from the base address of the ARITH unit.
 *
 * \param[in] IDX  is the expansion index
 *                 (possible values are between 0 and 383 included)
 *                 minimum and maximum value can be retrieved by using the ATON_ARITH_COEFF_AB_IDX_MIN and ATON_ARITH_COEFF_AB_IDX_MAX macros
 *
 * \return the offset of the ARITH.COEFF_AB register of ARITH unit template
 *         corresponding to the values of the expansion index (\e idx) equal to the function parameter \e IDX
 */

#define ATON_ARITH_COEFF_AB_OFFSET(IDX) \
  ((((IDX) >= INT32_C(0)) && ((IDX) < INT32_C(384))) ? (UINT32_C(1024) + (IDX) * UINT32_C(8)) : UINT32_C(0))


/**
 * Get the address of one of the ARITH.COEFF_AB registers of the ARITH unit.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'ARITH_0'
 *                 - UNIT == 1: 'ARITH_1'
 * \param[in] IDX  is the expansion index
 *                 (possible values are between 0 and 383 included)
 *                 minimum and maximum value can be retrieved by using the ATON_ARITH_COEFF_AB_IDX_MIN and ATON_ARITH_COEFF_AB_IDX_MAX macros
 *
 * \return the address of the ARITH.COEFF_AB register of ARITH unit template
 *         corresponding to the values of the expansion index (\e idx) equal to the function parameter \e IDX
 */

#define ATON_ARITH_COEFF_AB_ADDR(UNIT, IDX) \
  (ATON_ARITH_BASE(UNIT) + ATON_ARITH_COEFF_AB_OFFSET(IDX))


