/**
 * Read the value of one of the ARITH.COEFF_AB registers of one of the ARITH units.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'ARITH_0'
 *                 - UNIT == 1: 'ARITH_1'
 * \param[in] IDX  is the expansion index
 *                 (possible values are between 0 and 383 included)
 *                 minimum and maximum value can be retrieved by using the ATON_ARITH_COEFF_AB_IDX_MIN and ATON_ARITH_COEFF_AB_IDX_MAX macros
 *
 * \return the value of the ARITH.COEFF_AB register of ARITH unit template instance having index \e UNIT
 *         corresponding to the values of the expansion index (\e idx) equal to the function parameter \e IDX
 */

#define ATON_ARITH_COEFF_AB_GET(UNIT, IDX) \
  ATON_GET_REG32(ATON_ARITH_COEFF_AB_ADDR(UNIT, IDX))


/**
 * Write the value of one of the ARITH.COEFF_AB registers of one of the ARITH units.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'ARITH_0'
 *                 - UNIT == 1: 'ARITH_1'
 * \param[in] IDX  is the expansion index
 *                 (possible values are between 0 and 383 included)
 *                 minimum and maximum value can be retrieved by using the ATON_ARITH_COEFF_AB_IDX_MIN and ATON_ARITH_COEFF_AB_IDX_MAX macros
 * \param[in] DATA is the value that must be written to the register
 */

#define ATON_ARITH_COEFF_AB_SET(UNIT, IDX, DATA) \
  do { ATON_SET_REG32(ATON_ARITH_COEFF_AB_ADDR(UNIT, IDX), DATA); } while (0)


/* ----------------------------------------------------------------------------- A field of the ARITH.COEFF_AB register ----------------------------------------------------------------------------- */

/** Size in bits of the A field of the ARITH.COEFF_AB register. */
#define ATON_ARITH_COEFF_AB_A_W  UINT32_C(16)

/** Offset of the A field of the ARITH.COEFF_AB register. */
#define ATON_ARITH_COEFF_AB_A_LSB  UINT32_C(0)


/** Reset value of the A fields of the ARITH.COEFF_AB register. */
#define ATON_ARITH_COEFF_AB_A_DT  UINT16_C(0x0)


/** Mask for retrieving the value of the A fields of the ARITH.COEFF_AB register. */
#define ATON_ARITH_COEFF_AB_A_MASK ATON_FIELD_MASK32(ATON_ARITH_COEFF_AB_A_LSB, ATON_ARITH_COEFF_AB_A_W)



/** If \e true, read accesses to the A field of the ARITH.COEFF_AB register are supported (otherwise reading the field will always return 0). */
#define ATON_ARITH_COEFF_AB_A_AC_R  true

/** If \e true, write accesses to the A field of the ARITH.COEFF_AB register are allowed. */
#define ATON_ARITH_COEFF_AB_A_AC_W  true

/** If \e true, accesses to the A field of the ARITH.COEFF_AB register are secure. */
#define ATON_ARITH_COEFF_AB_A_AC_S  false

/** If \e true, accesses to the A field of the ARITH.COEFF_AB register are privileged. */
#define ATON_ARITH_COEFF_AB_A_AC_P  false


/** Description of the A field of one of the ARITH.COEFF_AB registers. */
#define ATON_ARITH_COEFF_AB_A_DESC  "A field"


/**
 * Get the value of the A field of the ARITH.COEFF_AB register of one of the ARITH units.
 *
 * \param[in] REG  is the value of the ARITH.COEFF_AB register
 *
 * \return the value of the ARITH.COEFF_AB.A field of the ARITH.COEFF_AB register
 */

#define ATON_ARITH_COEFF_AB_GET_A(REG) \
  ATON_GET_FIELD32(REG, ATON_ARITH_COEFF_AB_A_LSB, ATON_ARITH_COEFF_AB_A_W)


/**
 * Set the value of the A field of the ARITH.COEFF_AB register of one of the ARITH units.
 *
 * \param[in] REG  is the value of the ARITH.COEFF_AB register
 * \param[in] DATA is the value that must be written to the field
 *
 * \return the new value of the ARITH.COEFF_AB register
 */

#define ATON_ARITH_COEFF_AB_SET_A(REG, DATA) \
  ATON_SET_FIELD32(REG, ATON_ARITH_COEFF_AB_A_LSB, ATON_ARITH_COEFF_AB_A_W, DATA)


/* ----------------------------------------------------------------------------- B field of the ARITH.COEFF_AB register ----------------------------------------------------------------------------- */

