/** Reset value of the B fields of the ARITH.COEFF_AB register. */
#define ATON_ARITH_COEFF_AB_B_DT  UINT16_C(0x0)


/** Mask for retrieving the value of the B fields of the ARITH.COEFF_AB register. */
#define ATON_ARITH_COEFF_AB_B_MASK ATON_FIELD_MASK32(ATON_ARITH_COEFF_AB_B_LSB, ATON_ARITH_COEFF_AB_B_W)



/** If \e true, read accesses to the B field of the ARITH.COEFF_AB register are supported (otherwise reading the field will always return 0). */
#define ATON_ARITH_COEFF_AB_B_AC_R  true

/** If \e true, write accesses to the B field of the ARITH.COEFF_AB register are allowed. */
#define ATON_ARITH_COEFF_AB_B_AC_W  true

/** If \e true, accesses to the B field of the ARITH.COEFF_AB register are secure. */
#define ATON_ARITH_COEFF_AB_B_AC_S  false

/** If \e true, accesses to the B field of the ARITH.COEFF_AB register are privileged. */
#define ATON_ARITH_COEFF_AB_B_AC_P  false


/** Description of the B field of one of the ARITH.COEFF_AB registers. */
#define ATON_ARITH_COEFF_AB_B_DESC  "B field"


/**
 * Get the value of the B field of the ARITH.COEFF_AB register of one of the ARITH units.
 *
 * \param[in] REG  is the value of the ARITH.COEFF_AB register
 *
 * \return the value of the ARITH.COEFF_AB.B field of the ARITH.COEFF_AB register
 */

#define ATON_ARITH_COEFF_AB_GET_B(REG) \
  ATON_GET_FIELD32(REG, ATON_ARITH_COEFF_AB_B_LSB, ATON_ARITH_COEFF_AB_B_W)


/**
 * Set the value of the B field of the ARITH.COEFF_AB register of one of the ARITH units.
 *
 * \param[in] REG  is the value of the ARITH.COEFF_AB register
 * \param[in] DATA is the value that must be written to the field
 *
 * \return the new value of the ARITH.COEFF_AB register
 */

#define ATON_ARITH_COEFF_AB_SET_B(REG, DATA) \
  ATON_SET_FIELD32(REG, ATON_ARITH_COEFF_AB_B_LSB, ATON_ARITH_COEFF_AB_B_W, DATA)


