/**
 * Read the value of one of the ARITH.COEFF_C registers of one of the ARITH units.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'ARITH_0'
 *                 - UNIT == 1: 'ARITH_1'
 * \param[in] IDX  is the expansion index
 *                 (possible values are between 0 and 383 included)
 *                 minimum and maximum value can be retrieved by using the ATON_ARITH_COEFF_C_IDX_MIN and ATON_ARITH_COEFF_C_IDX_MAX macros
 *
 * \return the value of the ARITH.COEFF_C register of ARITH unit template instance having index \e UNIT
 *         corresponding to the values of the expansion index (\e idx) equal to the function parameter \e IDX
 */

#define ATON_ARITH_COEFF_C_GET(UNIT, IDX) \
  ATON_GET_REG32(ATON_ARITH_COEFF_C_ADDR(UNIT, IDX))


/**
 * Write the value of one of the ARITH.COEFF_C registers of one of the ARITH units.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'ARITH_0'
 *                 - UNIT == 1: 'ARITH_1'
 * \param[in] IDX  is the expansion index
 *                 (possible values are between 0 and 383 included)
 *                 minimum and maximum value can be retrieved by using the ATON_ARITH_COEFF_C_IDX_MIN and ATON_ARITH_COEFF_C_IDX_MAX macros
 * \param[in] DATA is the value that must be written to the register
 */

#define ATON_ARITH_COEFF_C_SET(UNIT, IDX, DATA) \
  do { ATON_SET_REG32(ATON_ARITH_COEFF_C_ADDR(UNIT, IDX), DATA); } while (0)


/* ----------------------------------------------------------------------------- C field of the ARITH.COEFF_C register ------------------------------------------------------------------------------ */

/** Size in bits of the C field of the ARITH.COEFF_C register. */
#define ATON_ARITH_COEFF_C_C_W  UINT32_C(16)

/** Offset of the C field of the ARITH.COEFF_C register. */
#define ATON_ARITH_COEFF_C_C_LSB  UINT32_C(0)


/** Reset value of the C fields of the ARITH.COEFF_C register. */
#define ATON_ARITH_COEFF_C_C_DT  UINT16_C(0x0)


/** Mask for retrieving the value of the C fields of the ARITH.COEFF_C register. */
#define ATON_ARITH_COEFF_C_C_MASK ATON_FIELD_MASK32(ATON_ARITH_COEFF_C_C_LSB, ATON_ARITH_COEFF_C_C_W)



/** If \e true, read accesses to the C field of the ARITH.COEFF_C register are supported (otherwise reading the field will always return 0). */
#define ATON_ARITH_COEFF_C_C_AC_R  true

/** If \e true, write accesses to the C field of the ARITH.COEFF_C register are allowed. */
#define ATON_ARITH_COEFF_C_C_AC_W  true

/** If \e true, accesses to the C field of the ARITH.COEFF_C register are secure. */
#define ATON_ARITH_COEFF_C_C_AC_S  false

/** If \e true, accesses to the C field of the ARITH.COEFF_C register are privileged. */
#define ATON_ARITH_COEFF_C_C_AC_P  false


/** Description of the C field of one of the ARITH.COEFF_C registers. */
#define ATON_ARITH_COEFF_C_C_DESC  "C field"


/**
 * Get the value of the C field of the ARITH.COEFF_C register of one of the ARITH units.
 *
 * \param[in] REG  is the value of the ARITH.COEFF_C register
 *
 * \return the value of the ARITH.COEFF_C.C field of the ARITH.COEFF_C register
 */

#define ATON_ARITH_COEFF_C_GET_C(REG) \
  ATON_GET_FIELD32(REG, ATON_ARITH_COEFF_C_C_LSB, ATON_ARITH_COEFF_C_C_W)


/**
 * Set the value of the C field of the ARITH.COEFF_C register of one of the ARITH units.
 *
 * \param[in] REG  is the value of the ARITH.COEFF_C register
 * \param[in] DATA is the value that must be written to the field
 *
 * \return the new value of the ARITH.COEFF_C register
 */

#define ATON_ARITH_COEFF_C_SET_C(REG, DATA) \
  ATON_SET_FIELD32(REG, ATON_ARITH_COEFF_C_C_LSB, ATON_ARITH_COEFF_C_C_W, DATA)


