/** Size in bytes of the BUSIF units. */
#define ATON_BUSIF_SIZE  UINT32_C(0x1000)


/**
 * Get the base address of one of the BUSIF units.
 *
 * \param[in] UNIT is the index of the BUSIF unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: BUSIF_0
 *
 * \return the base address of unit having index \e UNIT among the BUSIF units
 */

#define ATON_BUSIF_BASE(UNIT) \
  (((UNIT) < 1) ? (ATON_BASE + UINT32_C(0x2000)) : 0)


/**
 * Get the pointer to one of the BUSIF units.
 *
 * \param[in] UNIT is the index of the BUSIF ;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: BUSIF_0
 *
 * \return the pointer to unit having index \e UNIT among the BUSIF units
 */

#define ATON_BUSIF_PTR(UNIT) \
  ((volatile uint32_t *)(intptr_t)ATON_BUSIF_BASE(UNIT))


