/**
 * Get the minimum possible value of idx expansion index (expansion index) of BUSIF.CTRL.KEY_VALID register fields.
 *
 * \return the minimum possible value of idx expansion index (expansion index) of BUSIF.CTRL.KEY_VALID register fields
 */

#define ATON_BUSIF_CTRL_KEY_VALID_IDX_MIN   0


/**
 * Get the maximum possible value of idx expansion index (expansion index) of BUSIF.CTRL.KEY_VALID register fields.
 *
 * \return the maximum possible value of idx expansion index (expansion index) of BUSIF.CTRL.KEY_VALID register fields
 */

#define ATON_BUSIF_CTRL_KEY_VALID_IDX_MAX   1


/**
 * Get the identifier of one of the KEY_VALID fields of the BUSIF.CTRL register.
 *
 * \param[in] IDX  is the expansion index
 *                 (possible values are between 0 and 1 included)
 *                 minimum and maximum value can be retrieved by using the ATON_BUSIF_CTRL_KEY_VALID_IDX_MIN and ATON_BUSIF_CTRL_KEY_VALID_IDX_MAX macros
 *
 * \return the identifier of the KEY_VALID field of BUSIF.CTRL register of BUSIF unit template
 *         corresponding to the values of the expansion index (\e idx) equal to the macro parameter \e IDX
 */

#define ATON_BUSIF_CTRL_KEY_VALID_ID(IDX) \
  ((const volatile uint8_t *)(((IDX) == 0) ? "KEY0_VALID" : \
                     ((IDX) == 1) ? "KEY1_VALID" : \
                     ""))


/** Size in bits of the KEY_VALID fields of the BUSIF.CTRL register. */
#define ATON_BUSIF_CTRL_KEY_VALID_W  UINT32_C(1)

/**
 * Get the offset of one of the KEY_VALID fields of the BUSIF.CTRL register.
 *
 * \param[in] IDX  is the expansion index
 *                 (possible values are between 0 and 1 included)
 *                 minimum and maximum value can be retrieved by using the ATON_BUSIF_CTRL_KEY_VALID_IDX_MIN and ATON_BUSIF_CTRL_KEY_VALID_IDX_MAX macros
 *
 * \return the offset of the KEY_VALID field of BUSIF.CTRL register of BUSIF unit template
 *         corresponding to the values of the expansion index (\e idx) equal to the macro parameter \e IDX
 */

#define ATON_BUSIF_CTRL_KEY_VALID_LSB(IDX) \
  ((((IDX) >= INT32_C(0)) && ((IDX) < INT32_C(2))) ? ((IDX) + UINT32_C(16)) : 0)


/** Reset value of the KEY_VALID fields of the BUSIF.CTRL register. */
#define ATON_BUSIF_CTRL_KEY_VALID_DT  UINT8_C(0x0)


/**
 * Get the mask for retrieving the value of one of the KEY_VALID fields of the BUSIF.CTRL register.
 *
 * \param[in] IDX  is the expansion index
 *                 (possible values are between 0 and 1 included)
 *                 minimum and maximum value can be retrieved by using the ATON_BUSIF_CTRL_KEY_VALID_IDX_MIN and ATON_BUSIF_CTRL_KEY_VALID_IDX_MAX macros
 *
 * \return the mask for retrieving the value of the KEY_VALID field of BUSIF.CTRL register of BUSIF unit template
 *         corresponding to the values of the expansion index (\e idx) equal to the macro parameter \e IDX
 */

#define ATON_BUSIF_CTRL_KEY_VALID_MASK(IDX) \
  ATON_FIELD_MASK32(ATON_BUSIF_CTRL_KEY_VALID_LSB(IDX), ATON_BUSIF_CTRL_KEY_VALID_W)



/** If \e true, read accesses to the KEY_VALID fields of the BUSIF.CTRL register are supported (otherwise reading the field will always return 0). */
#define ATON_BUSIF_CTRL_KEY_VALID_AC_R  true

/** If \e true, write accesses to the KEY_VALID fields of the BUSIF.CTRL register are allowed. */
#define ATON_BUSIF_CTRL_KEY_VALID_AC_W  false

/** If \e true, accesses to the KEY_VALID fields of the BUSIF.CTRL register are secure. */
#define ATON_BUSIF_CTRL_KEY_VALID_AC_S  false

/** If \e true, accesses to the KEY_VALID fields of the BUSIF.CTRL register are privileged. */
#define ATON_BUSIF_CTRL_KEY_VALID_AC_P  false


/**
 * Get the description of one of the KEY_VALID fields of the BUSIF.CTRL register.
 *
 * \param[in] IDX  is the expansion index
 *                 (possible values are between 0 and 1 included)
 *                 minimum and maximum value can be retrieved by using the ATON_BUSIF_CTRL_KEY_VALID_IDX_MIN and ATON_BUSIF_CTRL_KEY_VALID_IDX_MAX macros
 *
 * \return the description of the KEY_VALID field of BUSIF.CTRL register of BUSIF unit template
 *         corresponding to the values of the expansion index (\e idx) equal to the macro parameter \e IDX
 */

#define ATON_BUSIF_CTRL_KEY_VALID_DESC(IDX) \
  ((const volatile uint8_t *)(((IDX) == 0) ? "Reports key 0 validity" : \
                     ((IDX) == 1) ? "Reports key 1 validity" : \
                     ""))


/**
 * Get the value of one of the KEY_VALID fields of the BUSIF.CTRL register of one of the BUSIF units.
 *
 * \param[in] REG  is the value of the BUSIF.CTRL register
 * \param[in] IDX  is the expansion index
 *                 (possible values are between 0 and 1 included)
 *                 minimum and maximum value can be retrieved by using the ATON_BUSIF_CTRL_KEY_VALID_IDX_MIN and ATON_BUSIF_CTRL_KEY_VALID_IDX_MAX macros
 *
 * \return the value of the BUSIF.CTRL.KEY_VALID field of the BUSIF.CTRL register
 *         corresponding to the values of the expansion index (\e idx) equal to the macro parameter \e IDX
 */

#define ATON_BUSIF_CTRL_GET_KEY_VALID(REG, IDX) \
  ATON_GET_FIELD32(REG, ATON_BUSIF_CTRL_KEY_VALID_LSB(IDX), ATON_BUSIF_CTRL_KEY_VALID_W)


/**
 * Ignore a modification of the value of one of the KEY_VALID read-only fields of the BUSIF.CTRL register of one of the BUSIF units.
 *
 * \param[in] REG  is ignored
 * \param[in] IDX  is ignored
 * \param[in] DATA is ignored
 *
 * \return the value of the BUSIF.CTRL register
 *         corresponding to the values of the expansion index (\e idx) equal to the macro parameter \e IDX
 */

#define ATON_BUSIF_CTRL_SET_KEY_VALID(REG, IDX, DATA) \
  (ATON_RO_ERROR((const uint8_t *)"BUSIF.CTRL.KEY_VALID is a read-only register field"), REG)


