/**
 * \name Macros of the CONVACC units
 */
/*@{*/

/** Number of CONVACC unit instances. */
#define ATON_CONVACC_NUM 1

/** Size in bytes of the CONVACC units. */
#define ATON_CONVACC_SIZE  UINT32_C(0x1000)


/**
 * Get the base address of one of the CONVACC units.
 *
 * \param[in] UNIT is the index of the CONVACC unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: CONVACC_0
 *
 * \return the base address of unit having index \e UNIT among the CONVACC units
 */

#define ATON_CONVACC_BASE(UNIT) \
  (((UNIT) < 1) ? (ATON_BASE + UINT32_C(0xa000)) : 0)


/**
 * Get the pointer to one of the CONVACC units.
 *
 * \param[in] UNIT is the index of the CONVACC ;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: CONVACC_0
 *
 * \return the pointer to unit having index \e UNIT among the CONVACC units
 */

#define ATON_CONVACC_PTR(UNIT) \
  ((volatile uint32_t *)(intptr_t)ATON_CONVACC_BASE(UNIT))


/**
 * Get the identifier of one of the CONVACC units.
 *
 * \param[in] UNIT is the index of the CONVACC unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: CONVACC_0
 *
 * \return the identifier of unit having index \e UNIT among the CONVACC units
 */

#define ATON_CONVACC_ID(UNIT) \
  ((const volatile uint8_t *)(((UNIT) < 1) ? "CONVACC_0" : ""))


/**
 * Get the description of one of the CONVACC units.
 *
 * \param[in] UNIT is the index of the CONVACC unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: CONVACC_0
 *
 * \return the description of unit having index \e UNIT among the CONVACC units
 */

#define ATON_CONVACC_DESC(UNIT) \
  ((const volatile uint8_t *)(((UNIT) < 1) ? "Convolutional Accelerator 0" : ""))


/** Version of the CONVACC units. */
#define ATON_CONVACC_VERSION "7.2"


/**
 * Get the IP number of one of the CONVACC units.
 *
 * \param[in] UNIT is the index of the CONVACC unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: CONVACC_0
 *
 * \return the IP number of unit having index \e UNIT among the CONVACC units
 */

#define ATON_CONVACC_IP_NUMBER(UNIT) \
  ((uint32_t)(((UNIT) < 1) ? 6 : 0))


/**
 * Get the value of the CONVACC_CONF parameter for one of the CONVACC units.
 *
 * \param[in] UNIT is the index of the CONVACC unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: CONVACC_0
 *
 * \return the value of the CONVACC_CONF parameter for unit having index \e UNIT among the CONVACC units
 */

#define ATON_CONVACC_PARAM_CONVACC_CONF(UNIT) \
  (((UNIT) < 1) ? 0x2 : 0)


/**
 * Get the value of the CONVACC_FF_DPMEM parameter for one of the CONVACC units.
 *
 * \param[in] UNIT is the index of the CONVACC unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: CONVACC_0
 *
 * \return the value of the CONVACC_FF_DPMEM parameter for unit having index \e UNIT among the CONVACC units
 */

#define ATON_CONVACC_PARAM_CONVACC_FF_DPMEM(UNIT) \
  (((UNIT) < 1) ? 0x1 : 0)


/**
 * Get the index of the destination Clock Controller unit of one of the CLKB clocks defined by one of the CONVACC units.
 * Clock Controller indices are the following:
 * -  0: CLKCTRL_0
 *
 * \param[in] UNIT is the index of the CONVACC unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: CONVACC_0
 *
 * \return the index of the destination Clock Controller unit of CLKB clock defined by CONVACC unit having index \e UNIT
 */

#define ATON_CONVACC_CLKB_CLKCTRL(UNIT) \
  (((UNIT) < 1) ? 0 : UINT_MAX)


/**
 * Get the index of CLKB clock in the destination Clock Controller unit.
 *
 * \param[in] UNIT is the index of the CONVACC unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: CONVACC_0
 *
 * \return the index of CLKB clock in the destination Clock Controller unit considering CONVACC unit having index \e UNIT
 */

#define ATON_CONVACC_CLKB_CLK(UNIT) \
  (((UNIT) < 1) ? 6 : 0)


/**
 * Return the mask of clock CLKB of one of the CONVACC units.
 *
 * \param[in] UNIT    if less than #ATON_CONVACC_NUM is the CONVACC instance index, otherwise if this value is equal to #ATON_CONVACC_NUM it indicates
 *                    that all instances whose CLKB clocks are connected to the same Clock Controller will be considered
 * \param[in] CLKCTRL is the index of the Clock Controller that must be considered:
 *                    -  0: CLKCTRL_0
 * \param[in] REG_IDX is the Clock Controller register index; its value must be less than 1
 *
 * \retval the mask of CLKB clock of a single CONVACC instance if \e UNIT is less than #ATON_CONVACC_NUM
 * \retval the mask of CLKB clock of all CONVACC instances if \e UNIT is equal to #ATON_CONVACC_NUM
 * \retval \e 0 if the values of \e UNIT, \e CLKCTRL or \e REG_IDX are not allowed
 */

#define ATON_CONVACC_CLK_CLKB_MASK(UNIT, CLKCTRL, REG_IDX) \
  ((((CLKCTRL) == 0) && ((REG_IDX) == 0) && ((UNIT) == 0)) ? UINT32_C(0x40) : \
   (((CLKCTRL) == 0) && ((REG_IDX) == 0) && ((UNIT) == 1)) ? UINT32_C(0x40) : \
   UINT32_C(0x0))



/**
 * Get the number of interrupts used by one of the CONVACC units.
 *
 * \param[in] UNIT is the index of the CONVACC unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: CONVACC_0
 *
 * \return the number of interrupts used by unit having index \e UNIT among the CONVACC units.
 */

#define ATON_CONVACC_INT_NUM(UNIT) \
  (((UNIT) < 1) ? 1 : 0)


/**
 * Get the index of the destination Interrupt Controller unit of interrupt pin 0 defined by one of the CONVACC units.
 * Interrupt Controller indices are the following:
 * -  0: INTCTRL_0
 *
 * \param[in] UNIT is the index of the CONVACC unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: CONVACC_0
 *
 * \return the index of the destination Interrupt Controller unit of interrupt pin 0 defined by CONVACC unit having index \e UNIT
 */

#define ATON_CONVACC_INTCTRL(UNIT) \
  (((UNIT) < 1) ? 0 : UINT_MAX)


/** Get the index in the destination Interrupt Controller unit of interrupt pin 0 defined by one of the CONVACC units.
 *
 * \param[in] UNIT is the index of the CONVACC unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: CONVACC_0
 *
 * \return the index in the destination Interrupt Controller unit of interrupt pin 0 defined by CONVACC unit having index \e UNIT, or #UINT_MAX if such interrupt pin is not
 *         connected to any Interrupt Controller unit
 */

#define ATON_CONVACC_INT(UNIT) \
  (((UNIT) < 1) ? 12 : UINT_MAX)


/**
 * Return the interrupt mask of a CONVACC unit.
 *
 * \param[in] UNIT    if less than #ATON_CONVACC_NUM is the CONVACC instance index, otherwise if this value is equal to #ATON_CONVACC_NUM it indicates
 *                    that all instances whose interrupt pins are connected to the same Interrupt Controller will be considered
 * \param[in] INTCTRL is the index of the Interrupt Controller that must be considered:
 *                    -  0: INTCTRL_0
 * \param[in] REG_IDX is the Interrupt Controller register index; its value must be less than 1
 *
 * \retval the interrupt mask of a single CONVACC instance if \e UNIT is less than #ATON_CONVACC_NUM
 * \retval the interrupt mask of all CONVACC instances if \e UNIT is equal to #ATON_CONVACC_NUM
 * \retval \e 0 if the values of \e UNIT, \e INTCTRL or \e REG_IDX are not allowed
 */

#define ATON_CONVACC_INT_MASK(UNIT, INTCTRL, REG_IDX) \
  ((((INTCTRL) == 0) && ((REG_IDX) == 0) && ((UNIT) == 0)) ? UINT32_C(0x1000) : \
   (((INTCTRL) == 0) && ((REG_IDX) == 0) && ((UNIT) == 1)) ? UINT32_C(0x1000) : \
   UINT32_C(0x0))



/**
 * Return 4 plus the offset of the last register of one of the CONVACC units.
 *
 * \param[in] UNIT is the index of the CONVACC unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: CONVACC_0
 *
 * \return 4 plus the offset of the last register defined by CONVACC unit having index \e UNIT
 */

#define ATON_CONVACC_LAST_REG_OFFSET(UNIT) \
  (((UNIT) < 1) ? 68 : 0)


/**
 * Check if the register having the given offset exists in one of the CONVACC units.
 *
 * \param[in] UNIT   is the index of the CONVACC unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: CONVACC_0
 * \param[in] OFFSET is the offset of the register that must be considered
 *
 * \retval \e true  if register having offset equal to \e offset exists in CONVACC unit having index \e UNIT
 * \retval \e false otherwise
 */

#define ATON_CONVACC_REG_OFFSET_EXISTS(UNIT, OFFSET) \
  ((((UNIT) < 1) && (((OFFSET) / 4) < 17)) ? true : false)


/* *************************************************************************** CTRL register of one of the CONVACC units **************************************************************************** */

/** Offset of the CONVACC.CTRL register from the base address of the CONVACC unit. */
#define ATON_CONVACC_CTRL_OFFSET  UINT32_C(0x0)

/**
 * Get the address of the CONVACC.CTRL register of the CONVACC unit.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'CONVACC_0'
 *
 * \return the address of the CONVACC.CTRL register of CONVACC unit template
 */

#define ATON_CONVACC_CTRL_ADDR(UNIT) \
  (ATON_CONVACC_BASE(UNIT) + ATON_CONVACC_CTRL_OFFSET)


/** Reset value of the CONVACC.CTRL register of the CONVACC unit. */
#define ATON_CONVACC_CTRL_DT  UINT32_C(0x00000000)


/** Read-write access rights mask of the CONVACC.CTRL register of the CONVACC unit. */
#define ATON_CONVACC_CTRL_RW  UINT32_C(0x7dffff7f)

/** Read-only access rights mask of the CONVACC.CTRL register of the CONVACC unit. */
#define ATON_CONVACC_CTRL_RO  UINT32_C(0x82000000)

/** Write-only access rights mask of the CONVACC.CTRL register of the CONVACC unit. */
#define ATON_CONVACC_CTRL_WO  UINT32_C(0x00000000)


/** Description of the CONVACC.CTRL register from the base address of the CONVACC unit. */
#define ATON_CONVACC_CTRL_DESC  "Control register"


/**
 * Read the value of the CONVACC.CTRL register of one of the CONVACC units.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'CONVACC_0'
 *
 * \return the value of the CONVACC.CTRL register of CONVACC unit template instance having index \e UNIT
 */

#define ATON_CONVACC_CTRL_GET(UNIT) \
  ATON_GET_REG32(ATON_CONVACC_CTRL_ADDR(UNIT))


/**
 * Write the value of the CONVACC.CTRL register of one of the CONVACC units.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'CONVACC_0'
 * \param[in] DATA is the value that must be written to the register
 */

#define ATON_CONVACC_CTRL_SET(UNIT, DATA) \
  do { ATON_SET_REG32(ATON_CONVACC_CTRL_ADDR(UNIT), DATA); } while (0)


