#define ATON_DEBUG_TRACE_LAST_REG_OFFSET(UNIT) \
  (((UNIT) < 1) ? 160 : 0)


/**
 * Check if the register having the given offset exists in one of the DEBUG_TRACE units.
 *
 * \param[in] UNIT   is the index of the DEBUG_TRACE unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: DEBUG_TRACE_0
 * \param[in] OFFSET is the offset of the register that must be considered
 *
 * \retval \e true  if register having offset equal to \e offset exists in DEBUG_TRACE unit having index \e UNIT
 * \retval \e false otherwise
 */

#define ATON_DEBUG_TRACE_REG_OFFSET_EXISTS(UNIT, OFFSET) \
  ((((UNIT) < 1) && (((OFFSET) / 4) < 40)) ? true : false)


