#define ATON_EPOCHCTRL_BC_OFFSET  UINT32_C(0x24)

/**
 * Get the address of the EPOCHCTRL.BC register of the EPOCHCTRL unit.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'EPOCHCTRL_0'
 *
 * \return the address of the EPOCHCTRL.BC register of EPOCHCTRL unit template
 */

#define ATON_EPOCHCTRL_BC_ADDR(UNIT) \
  (ATON_EPOCHCTRL_BASE(UNIT) + ATON_EPOCHCTRL_BC_OFFSET)


/** Reset value of the EPOCHCTRL.BC register of the EPOCHCTRL unit. */
#define ATON_EPOCHCTRL_BC_DT  UINT32_C(0x00000000)


/** Read-write access rights mask of the EPOCHCTRL.BC register of the EPOCHCTRL unit. */
#define ATON_EPOCHCTRL_BC_RW  UINT32_C(0x00000000)

/** Read-only access rights mask of the EPOCHCTRL.BC register of the EPOCHCTRL unit. */
#define ATON_EPOCHCTRL_BC_RO  UINT32_C(0x0000ffff)

/** Write-only access rights mask of the EPOCHCTRL.BC register of the EPOCHCTRL unit. */
#define ATON_EPOCHCTRL_BC_WO  UINT32_C(0x00000000)


/** Description of the EPOCHCTRL.BC register from the base address of the EPOCHCTRL unit. */
#define ATON_EPOCHCTRL_BC_DESC  "Blob opcode counter"


/**
 * Read the value of the EPOCHCTRL.BC register of one of the EPOCHCTRL units.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'EPOCHCTRL_0'
 *
 * \return the value of the EPOCHCTRL.BC register of EPOCHCTRL unit template instance having index \e UNIT
 */

#define ATON_EPOCHCTRL_BC_GET(UNIT) \
  ATON_GET_REG32(ATON_EPOCHCTRL_BC_ADDR(UNIT))


/**
 * Ignore a modification of the value of the EPOCHCTRL.BC read-only register of one of the EPOCHCTRL units.
 *
 * \param[in] UNIT is ignored
 * \param[in] DATA is ignored
 */

#define ATON_EPOCHCTRL_BC_SET(UNIT, DATA) \
  do { ATON_RO_ERROR((const uint8_t *)"EPOCHCTRL.BC is a read-only register"); } while (0)


/* ----------------------------------------------------------------------------- CNT field of the EPOCHCTRL.BC register ----------------------------------------------------------------------------- */

/** Size in bits of the CNT field of the EPOCHCTRL.BC register. */
#define ATON_EPOCHCTRL_BC_CNT_W  UINT32_C(16)

/** Offset of the CNT field of the EPOCHCTRL.BC register. */
#define ATON_EPOCHCTRL_BC_CNT_LSB  UINT32_C(0)


/** Reset value of the CNT fields of the EPOCHCTRL.BC register. */
#define ATON_EPOCHCTRL_BC_CNT_DT  UINT16_C(0x0)


/** Mask for retrieving the value of the CNT fields of the EPOCHCTRL.BC register. */
#define ATON_EPOCHCTRL_BC_CNT_MASK ATON_FIELD_MASK32(ATON_EPOCHCTRL_BC_CNT_LSB, ATON_EPOCHCTRL_BC_CNT_W)



/** If \e true, read accesses to the CNT field of the EPOCHCTRL.BC register are supported (otherwise reading the field will always return 0). */
#define ATON_EPOCHCTRL_BC_CNT_AC_R  true

/** If \e true, write accesses to the CNT field of the EPOCHCTRL.BC register are allowed. */
#define ATON_EPOCHCTRL_BC_CNT_AC_W  false

/** If \e true, accesses to the CNT field of the EPOCHCTRL.BC register are secure. */
#define ATON_EPOCHCTRL_BC_CNT_AC_S  false

/** If \e true, accesses to the CNT field of the EPOCHCTRL.BC register are privileged. */
#define ATON_EPOCHCTRL_BC_CNT_AC_P  false


/** Description of the CNT field of the EPOCHCTRL.BC register. */
#define ATON_EPOCHCTRL_BC_CNT_DESC  "Blob opcode counter"


/**
 * Get the value of the CNT field of the EPOCHCTRL.BC register of one of the EPOCHCTRL units.
 *
 * \param[in] REG  is the value of the EPOCHCTRL.BC register
 *
 * \return the value of the EPOCHCTRL.BC.CNT field of the EPOCHCTRL.BC register
 */

#define ATON_EPOCHCTRL_BC_GET_CNT(REG) \
  ATON_GET_FIELD32(REG, ATON_EPOCHCTRL_BC_CNT_LSB, ATON_EPOCHCTRL_BC_CNT_W)


/**
 * Ignore a modification of the value of the CNT read-only field of the EPOCHCTRL.BC register of one of the EPOCHCTRL units.
 *
 * \param[in] REG  is ignored
 * \param[in] DATA is ignored
 *
 * \return the value of the EPOCHCTRL.BC register
 */

#define ATON_EPOCHCTRL_BC_SET_CNT(REG, DATA) \
  (ATON_RO_ERROR((const uint8_t *)"EPOCHCTRL.BC.CNT is a read-only register field"), REG)


/* *************************************************************************** ACC register of one of the EPOCHCTRL units *************************************************************************** */

/** Offset of the EPOCHCTRL.ACC register from the base address of the EPOCHCTRL unit. */
#define ATON_EPOCHCTRL_ACC_OFFSET  UINT32_C(0x28)

/**
 * Get the address of the EPOCHCTRL.ACC register of the EPOCHCTRL unit.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'EPOCHCTRL_0'
 *
 * \return the address of the EPOCHCTRL.ACC register of EPOCHCTRL unit template
 */

#define ATON_EPOCHCTRL_ACC_ADDR(UNIT) \
  (ATON_EPOCHCTRL_BASE(UNIT) + ATON_EPOCHCTRL_ACC_OFFSET)


/** Reset value of the EPOCHCTRL.ACC register of the EPOCHCTRL unit. */
#define ATON_EPOCHCTRL_ACC_DT  UINT32_C(0x00000000)


/** Read-write access rights mask of the EPOCHCTRL.ACC register of the EPOCHCTRL unit. */
#define ATON_EPOCHCTRL_ACC_RW  UINT32_C(0x00000000)

/** Read-only access rights mask of the EPOCHCTRL.ACC register of the EPOCHCTRL unit. */
#define ATON_EPOCHCTRL_ACC_RO  UINT32_C(0xffffffff)

/** Write-only access rights mask of the EPOCHCTRL.ACC register of the EPOCHCTRL unit. */
#define ATON_EPOCHCTRL_ACC_WO  UINT32_C(0x00000000)


/** Description of the EPOCHCTRL.ACC register from the base address of the EPOCHCTRL unit. */
#define ATON_EPOCHCTRL_ACC_DESC  "Accumulator"


/**
 * Read the value of the EPOCHCTRL.ACC register of one of the EPOCHCTRL units.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'EPOCHCTRL_0'
 *
 * \return the value of the EPOCHCTRL.ACC register of EPOCHCTRL unit template instance having index \e UNIT
 */

#define ATON_EPOCHCTRL_ACC_GET(UNIT) \
  ATON_GET_REG32(ATON_EPOCHCTRL_ACC_ADDR(UNIT))


/**
 * Ignore a modification of the value of the EPOCHCTRL.ACC read-only register of one of the EPOCHCTRL units.
 *
 * \param[in] UNIT is ignored
 * \param[in] DATA is ignored
 */

#define ATON_EPOCHCTRL_ACC_SET(UNIT, DATA) \
  do { ATON_RO_ERROR((const uint8_t *)"EPOCHCTRL.ACC is a read-only register"); } while (0)


/* ---------------------------------------------------------------------------- REG field of the EPOCHCTRL.ACC register ----------------------------------------------------------------------------- */

/** Size in bits of the REG field of the EPOCHCTRL.ACC register. */
#define ATON_EPOCHCTRL_ACC_REG_W  UINT32_C(32)

/** Offset of the REG field of the EPOCHCTRL.ACC register. */
#define ATON_EPOCHCTRL_ACC_REG_LSB  UINT32_C(0)


/** Reset value of the REG fields of the EPOCHCTRL.ACC register. */
#define ATON_EPOCHCTRL_ACC_REG_DT  UINT32_C(0x0)


/** Mask for retrieving the value of the REG fields of the EPOCHCTRL.ACC register. */
#define ATON_EPOCHCTRL_ACC_REG_MASK ATON_FIELD_MASK32(ATON_EPOCHCTRL_ACC_REG_LSB, ATON_EPOCHCTRL_ACC_REG_W)



/** If \e true, read accesses to the REG field of the EPOCHCTRL.ACC register are supported (otherwise reading the field will always return 0). */
#define ATON_EPOCHCTRL_ACC_REG_AC_R  true

/** If \e true, write accesses to the REG field of the EPOCHCTRL.ACC register are allowed. */
#define ATON_EPOCHCTRL_ACC_REG_AC_W  false

/** If \e true, accesses to the REG field of the EPOCHCTRL.ACC register are secure. */
#define ATON_EPOCHCTRL_ACC_REG_AC_S  false

/** If \e true, accesses to the REG field of the EPOCHCTRL.ACC register are privileged. */
#define ATON_EPOCHCTRL_ACC_REG_AC_P  false


/** Description of the REG field of the EPOCHCTRL.ACC register. */
#define ATON_EPOCHCTRL_ACC_REG_DESC  "Accumulator value"


/*@}*/


