/* -------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------- */

/**
 * \name Macros of the INTCTRL units
 */
/*@{*/

/** Number of INTCTRL unit instances. */
#define ATON_INTCTRL_NUM 1

/** Size in bytes of the INTCTRL units. */
#define ATON_INTCTRL_SIZE  UINT32_C(0x1000)


/**
 * Get the base address of one of the INTCTRL units.
 *
 * \param[in] UNIT is the index of the INTCTRL unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: INTCTRL_0
 *
 * \return the base address of unit having index \e UNIT among the INTCTRL units
 */

#define ATON_INTCTRL_BASE(UNIT) \
  (((UNIT) < 1) ? (ATON_BASE + UINT32_C(0x1000)) : 0)


/**
 * Get the pointer to one of the INTCTRL units.
 *
 * \param[in] UNIT is the index of the INTCTRL ;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: INTCTRL_0
 *
 * \return the pointer to unit having index \e UNIT among the INTCTRL units
 */

#define ATON_INTCTRL_PTR(UNIT) \
  ((volatile uint32_t *)(intptr_t)ATON_INTCTRL_BASE(UNIT))


/**
 * Get the identifier of one of the INTCTRL units.
 *
 * \param[in] UNIT is the index of the INTCTRL unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: INTCTRL_0
 *
 * \return the identifier of unit having index \e UNIT among the INTCTRL units
 */

#define ATON_INTCTRL_ID(UNIT) \
  ((const volatile uint8_t *)(((UNIT) < 1) ? "INTCTRL_0" : ""))


/**
 * Get the description of one of the INTCTRL units.
 *
 * \param[in] UNIT is the index of the INTCTRL unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: INTCTRL_0
 *
 * \return the description of unit having index \e UNIT among the INTCTRL units
 */

#define ATON_INTCTRL_DESC(UNIT) \
  ((const volatile uint8_t *)(((UNIT) < 1) ? "Interrupt Controller" : ""))


/** Version of the INTCTRL units. */
#define ATON_INTCTRL_VERSION "2.1"


/**
 * Get the IP number of one of the INTCTRL units.
 *
 * \param[in] UNIT is the index of the INTCTRL unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: INTCTRL_0
 *
 * \return the IP number of unit having index \e UNIT among the INTCTRL units
 */

#define ATON_INTCTRL_IP_NUMBER(UNIT) \
  ((uint32_t)(((UNIT) < 1) ? 17 : 0))


/**
 * Get the index of the destination Clock Controller unit of one of the CLKA clocks defined by one of the INTCTRL units.
 * Clock Controller indices are the following:
 * -  0: CLKCTRL_0
 *
 * \param[in] UNIT is the index of the INTCTRL unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: INTCTRL_0
 *
 * \return the index of the destination Clock Controller unit of CLKA clock defined by INTCTRL unit having index \e UNIT
 */

#define ATON_INTCTRL_CLKA_CLKCTRL(UNIT) \
  (((UNIT) < 1) ? 0 : UINT_MAX)


/**
 * Get the index of CLKA clock in the destination Clock Controller unit.
 *
 * \param[in] UNIT is the index of the INTCTRL unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: INTCTRL_0
 *
 * \return the index of CLKA clock in the destination Clock Controller unit considering INTCTRL unit having index \e UNIT
 */

#define ATON_INTCTRL_CLKA_CLK(UNIT) \
  0


/**
 * Return the mask of clock CLKA of one of the INTCTRL units.
 *
 * \param[in] UNIT    if less than #ATON_INTCTRL_NUM is the INTCTRL instance index, otherwise if this value is equal to #ATON_INTCTRL_NUM it indicates
 *                    that all instances whose CLKA clocks are connected to the same Clock Controller will be considered
 * \param[in] CLKCTRL is the index of the Clock Controller that must be considered:
 *                    -  0: CLKCTRL_0
 * \param[in] REG_IDX is the Clock Controller register index; its value must be less than 1
 *
 * \retval the mask of CLKA clock of a single INTCTRL instance if \e UNIT is less than #ATON_INTCTRL_NUM
 * \retval the mask of CLKA clock of all INTCTRL instances if \e UNIT is equal to #ATON_INTCTRL_NUM
 * \retval \e 0 if the values of \e UNIT, \e CLKCTRL or \e REG_IDX are not allowed
 */

#define ATON_INTCTRL_CLK_CLKA_MASK(UNIT, CLKCTRL, REG_IDX) \
  ((((CLKCTRL) == 0) && ((REG_IDX) == 0) && ((UNIT) == 0)) ? UINT32_C(0x1) : \
   (((CLKCTRL) == 0) && ((REG_IDX) == 0) && ((UNIT) == 1)) ? UINT32_C(0x1) : \
   UINT32_C(0x0))



/**
 * Get the maximum number of interrupt plugs used by one of the INTCTRL units.
 *
 * \param[in] UNIT is the index of the INTCTRL unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: INTCTRL_0
 *
 * \return the maximum number of interrupt plugs used by unit having index \e UNIT among the INTCTRL units.
 */

#define ATON_INTCTRL_INTS(UNIT) \
  (((UNIT) < 1) ? 19 : 0)


/**
 * Return 4 plus the offset of the last register of one of the INTCTRL units.
 *
 * \param[in] UNIT is the index of the INTCTRL unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: INTCTRL_0
 *
 * \return 4 plus the offset of the last register defined by INTCTRL unit having index \e UNIT
 */

#define ATON_INTCTRL_LAST_REG_OFFSET(UNIT) \
  (((UNIT) < 1) ? 52 : 0)


/**
 * Check if the register having the given offset exists in one of the INTCTRL units.
 *
 * \param[in] UNIT   is the index of the INTCTRL unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: INTCTRL_0
 * \param[in] OFFSET is the offset of the register that must be considered
 *
 * \retval \e true  if register having offset equal to \e offset exists in INTCTRL unit having index \e UNIT
 * \retval \e false otherwise
 */

#define ATON_INTCTRL_REG_OFFSET_EXISTS(UNIT, OFFSET) \
  ((((UNIT) < 1) && (((OFFSET) / 4) < 13)) ? true : false)


/* *************************************************************************** CTRL register of one of the INTCTRL units **************************************************************************** */

/** Offset of the INTCTRL.CTRL register from the base address of the INTCTRL unit. */
#define ATON_INTCTRL_CTRL_OFFSET  UINT32_C(0x0)

/**
 * Get the address of the INTCTRL.CTRL register of the INTCTRL unit.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'INTCTRL_0'
 *
 * \return the address of the INTCTRL.CTRL register of INTCTRL unit template
 */

#define ATON_INTCTRL_CTRL_ADDR(UNIT) \
  (ATON_INTCTRL_BASE(UNIT) + ATON_INTCTRL_CTRL_OFFSET)


/** Reset value of the INTCTRL.CTRL register of the INTCTRL unit. */
#define ATON_INTCTRL_CTRL_DT  UINT32_C(0x00000000)


/** Read-write access rights mask of the INTCTRL.CTRL register of the INTCTRL unit. */
#define ATON_INTCTRL_CTRL_RW  UINT32_C(0x40000003)

/** Read-only access rights mask of the INTCTRL.CTRL register of the INTCTRL unit. */
#define ATON_INTCTRL_CTRL_RO  UINT32_C(0x00000000)

/** Write-only access rights mask of the INTCTRL.CTRL register of the INTCTRL unit. */
#define ATON_INTCTRL_CTRL_WO  UINT32_C(0x00000000)


/** Description of the INTCTRL.CTRL register from the base address of the INTCTRL unit. */
#define ATON_INTCTRL_CTRL_DESC  "Control register"


/**
 * Read the value of the INTCTRL.CTRL register of one of the INTCTRL units.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'INTCTRL_0'
 *
 * \return the value of the INTCTRL.CTRL register of INTCTRL unit template instance having index \e UNIT
 */

#define ATON_INTCTRL_CTRL_GET(UNIT) \
  ATON_GET_REG32(ATON_INTCTRL_CTRL_ADDR(UNIT))


/**
 * Write the value of the INTCTRL.CTRL register of one of the INTCTRL units.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'INTCTRL_0'
 * \param[in] DATA is the value that must be written to the register
 */

#define ATON_INTCTRL_CTRL_SET(UNIT, DATA) \
  do { ATON_SET_REG32(ATON_INTCTRL_CTRL_ADDR(UNIT), DATA); } while (0)


/* ----------------------------------------------------------------------------- EN field of the INTCTRL.CTRL register ------------------------------------------------------------------------------ */

/** Size in bits of the EN field of the INTCTRL.CTRL register. */
#define ATON_INTCTRL_CTRL_EN_W  UINT32_C(1)

/** Offset of the EN field of the INTCTRL.CTRL register. */
#define ATON_INTCTRL_CTRL_EN_LSB  UINT32_C(0)


/** Reset value of the EN fields of the INTCTRL.CTRL register. */
#define ATON_INTCTRL_CTRL_EN_DT  UINT8_C(0x0)


/** Mask for retrieving the value of the EN fields of the INTCTRL.CTRL register. */
#define ATON_INTCTRL_CTRL_EN_MASK ATON_FIELD_MASK32(ATON_INTCTRL_CTRL_EN_LSB, ATON_INTCTRL_CTRL_EN_W)



/** If \e true, read accesses to the EN field of the INTCTRL.CTRL register are supported (otherwise reading the field will always return 0). */
#define ATON_INTCTRL_CTRL_EN_AC_R  true

/** If \e true, write accesses to the EN field of the INTCTRL.CTRL register are allowed. */
#define ATON_INTCTRL_CTRL_EN_AC_W  true

/** If \e true, accesses to the EN field of the INTCTRL.CTRL register are secure. */
#define ATON_INTCTRL_CTRL_EN_AC_S  false

/** If \e true, accesses to the EN field of the INTCTRL.CTRL register are privileged. */
#define ATON_INTCTRL_CTRL_EN_AC_P  false


/** Description of the EN field of the INTCTRL.CTRL register. */
#define ATON_INTCTRL_CTRL_EN_DESC  "Enable the Interrupt Controller"


/**
 * Get the value of the EN field of the INTCTRL.CTRL register of one of the INTCTRL units.
 *
 * \param[in] REG  is the value of the INTCTRL.CTRL register
 *
 * \return the value of the INTCTRL.CTRL.EN field of the INTCTRL.CTRL register
 */

#define ATON_INTCTRL_CTRL_GET_EN(REG) \
  ATON_GET_FIELD32(REG, ATON_INTCTRL_CTRL_EN_LSB, ATON_INTCTRL_CTRL_EN_W)


/**
 * Set the value of the EN field of the INTCTRL.CTRL register of one of the INTCTRL units.
 *
 * \param[in] REG  is the value of the INTCTRL.CTRL register
 * \param[in] DATA is the value that must be written to the field
 *
 * \return the new value of the INTCTRL.CTRL register
 */

#define ATON_INTCTRL_CTRL_SET_EN(REG, DATA) \
  ATON_SET_FIELD32(REG, ATON_INTCTRL_CTRL_EN_LSB, ATON_INTCTRL_CTRL_EN_W, DATA)


/* ----------------------------------------------------------------------------- CLR field of the INTCTRL.CTRL register ----------------------------------------------------------------------------- */

/** Size in bits of the CLR field of the INTCTRL.CTRL register. */
#define ATON_INTCTRL_CTRL_CLR_W  UINT32_C(1)

