/** If \e true, read accesses to the CLR field of the INTCTRL.CTRL register are supported (otherwise reading the field will always return 0). */
#define ATON_INTCTRL_CTRL_CLR_AC_R  true

/** If \e true, write accesses to the CLR field of the INTCTRL.CTRL register are allowed. */
#define ATON_INTCTRL_CTRL_CLR_AC_W  true

/** If \e true, accesses to the CLR field of the INTCTRL.CTRL register are secure. */
#define ATON_INTCTRL_CTRL_CLR_AC_S  false

