/* ************************************************************************** VERSION register of one of the INTCTRL units ************************************************************************** */

/** Offset of the INTCTRL.VERSION register from the base address of the INTCTRL unit. */
#define ATON_INTCTRL_VERSION_OFFSET  UINT32_C(0x4)

/**
 * Get the address of the INTCTRL.VERSION register of the INTCTRL unit.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'INTCTRL_0'
 *
 * \return the address of the INTCTRL.VERSION register of INTCTRL unit template
 */

#define ATON_INTCTRL_VERSION_ADDR(UNIT) \
  (ATON_INTCTRL_BASE(UNIT) + ATON_INTCTRL_VERSION_OFFSET)


/**
 * Get the reset value of the INTCTRL.VERSION register of the INTCTRL unit.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'INTCTRL_0'
 *
 * \return the reset value of the INTCTRL.VERSION register of INTCTRL unit template instance having index \e UNIT
 */

#define ATON_INTCTRL_VERSION_DT(UNIT) \
  UINT32_C(0x413211e)


/** Read-write access rights mask of the INTCTRL.VERSION register of the INTCTRL unit. */
