/**
 * \name Macros of the POOL units
 */
/*@{*/

/** Number of POOL unit instances. */
#define ATON_POOL_NUM 1

/** Size in bytes of the POOL units. */
#define ATON_POOL_SIZE  UINT32_C(0x1000)


/**
 * Get the base address of one of the POOL units.
 *
 * \param[in] UNIT is the index of the POOL unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: POOL_0
 *
 * \return the base address of unit having index \e UNIT among the POOL units
 */

#define ATON_POOL_BASE(UNIT) \
  (((UNIT) < 1) ? (ATON_BASE + UINT32_C(0xe000)) : 0)


/**
 * Get the pointer to one of the POOL units.
 *
 * \param[in] UNIT is the index of the POOL ;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: POOL_0
 *
 * \return the pointer to unit having index \e UNIT among the POOL units
 */

#define ATON_POOL_PTR(UNIT) \
  ((volatile uint32_t *)(intptr_t)ATON_POOL_BASE(UNIT))


/**
 * Get the identifier of one of the POOL units.
 *
 * \param[in] UNIT is the index of the POOL unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: POOL_0
 *
 * \return the identifier of unit having index \e UNIT among the POOL units
 */

#define ATON_POOL_ID(UNIT) \
  ((const volatile uint8_t *)(((UNIT) < 1) ? "POOL_0" : ""))


/**
 * Get the description of one of the POOL units.
 *
 * \param[in] UNIT is the index of the POOL unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: POOL_0
 *
 * \return the description of unit having index \e UNIT among the POOL units
 */

#define ATON_POOL_DESC(UNIT) \
  ((const volatile uint8_t *)(((UNIT) < 1) ? "Pooling Accelerator 0" : ""))


/** Version of the POOL units. */
#define ATON_POOL_VERSION "3.1"


/**
 * Get the IP number of one of the POOL units.
 *
 * \param[in] UNIT is the index of the POOL unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: POOL_0
 *
 * \return the IP number of unit having index \e UNIT among the POOL units
 */

#define ATON_POOL_IP_NUMBER(UNIT) \
  ((uint32_t)(((UNIT) < 1) ? 10 : 0))


/**
 * Get the value of the MAX_BATCH_SIZE parameter for one of the POOL units.
 *
 * \param[in] UNIT is the index of the POOL unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: POOL_0
 *
 * \return the value of the MAX_BATCH_SIZE parameter for unit having index \e UNIT among the POOL units
 */

#define ATON_POOL_PARAM_MAX_BATCH_SIZE(UNIT) \
  (((UNIT) < 1) ? 0x8 : 0)


/**
 * Get the index of the destination Clock Controller unit of one of the CLKB clocks defined by one of the POOL units.
 * Clock Controller indices are the following:
 * -  0: CLKCTRL_0
 *
 * \param[in] UNIT is the index of the POOL unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: POOL_0
 *
 * \return the index of the destination Clock Controller unit of CLKB clock defined by POOL unit having index \e UNIT
 */

#define ATON_POOL_CLKB_CLKCTRL(UNIT) \
  (((UNIT) < 1) ? 0 : UINT_MAX)


/**
 * Get the index of CLKB clock in the destination Clock Controller unit.
 *
 * \param[in] UNIT is the index of the POOL unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: POOL_0
 *
 * \return the index of CLKB clock in the destination Clock Controller unit considering POOL unit having index \e UNIT
 */

#define ATON_POOL_CLKB_CLK(UNIT) \
  (((UNIT) < 1) ? 10 : 0)


/**
 * Return the mask of clock CLKB of one of the POOL units.
 *
 * \param[in] UNIT    if less than #ATON_POOL_NUM is the POOL instance index, otherwise if this value is equal to #ATON_POOL_NUM it indicates
 *                    that all instances whose CLKB clocks are connected to the same Clock Controller will be considered
 * \param[in] CLKCTRL is the index of the Clock Controller that must be considered:
 *                    -  0: CLKCTRL_0
 * \param[in] REG_IDX is the Clock Controller register index; its value must be less than 1
 *
 * \retval the mask of CLKB clock of a single POOL instance if \e UNIT is less than #ATON_POOL_NUM
 * \retval the mask of CLKB clock of all POOL instances if \e UNIT is equal to #ATON_POOL_NUM
 * \retval \e 0 if the values of \e UNIT, \e CLKCTRL or \e REG_IDX are not allowed
 */

#define ATON_POOL_CLK_CLKB_MASK(UNIT, CLKCTRL, REG_IDX) \
  ((((CLKCTRL) == 0) && ((REG_IDX) == 0) && ((UNIT) == 0)) ? UINT32_C(0x400) : \
   (((CLKCTRL) == 0) && ((REG_IDX) == 0) && ((UNIT) == 1)) ? UINT32_C(0x400) : \
   UINT32_C(0x0))



/**
 * Return 4 plus the offset of the last register of one of the POOL units.
 *
 * \param[in] UNIT is the index of the POOL unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: POOL_0
 *
 * \return 4 plus the offset of the last register defined by POOL unit having index \e UNIT
 */

#define ATON_POOL_LAST_REG_OFFSET(UNIT) \
  (((UNIT) < 1) ? 60 : 0)


/**
 * Check if the register having the given offset exists in one of the POOL units.
 *
 * \param[in] UNIT   is the index of the POOL unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: POOL_0
 * \param[in] OFFSET is the offset of the register that must be considered
 *
 * \retval \e true  if register having offset equal to \e offset exists in POOL unit having index \e UNIT
 * \retval \e false otherwise
 */

#define ATON_POOL_REG_OFFSET_EXISTS(UNIT, OFFSET) \
  ((((UNIT) < 1) && (((OFFSET) / 4) < 15)) ? true : false)


/* ***************************************************************************** CTRL register of one of the POOL units ***************************************************************************** */

/** Offset of the POOL.CTRL register from the base address of the POOL unit. */
#define ATON_POOL_CTRL_OFFSET  UINT32_C(0x0)

/**
 * Get the address of the POOL.CTRL register of the POOL unit.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'POOL_0'
 *
 * \return the address of the POOL.CTRL register of POOL unit template
 */

#define ATON_POOL_CTRL_ADDR(UNIT) \
  (ATON_POOL_BASE(UNIT) + ATON_POOL_CTRL_OFFSET)


/** Reset value of the POOL.CTRL register of the POOL unit. */
#define ATON_POOL_CTRL_DT  UINT32_C(0x00420000)


/** Read-write access rights mask of the POOL.CTRL register of the POOL unit. */
#define ATON_POOL_CTRL_RW  UINT32_C(0x4fffffff)

/** Read-only access rights mask of the POOL.CTRL register of the POOL unit. */
#define ATON_POOL_CTRL_RO  UINT32_C(0x00000000)

/** Write-only access rights mask of the POOL.CTRL register of the POOL unit. */
#define ATON_POOL_CTRL_WO  UINT32_C(0x00000000)


/** Description of the POOL.CTRL register from the base address of the POOL unit. */
#define ATON_POOL_CTRL_DESC  "Control register"


/**
 * Read the value of the POOL.CTRL register of one of the POOL units.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'POOL_0'
 *
 * \return the value of the POOL.CTRL register of POOL unit template instance having index \e UNIT
 */

#define ATON_POOL_CTRL_GET(UNIT) \
  ATON_GET_REG32(ATON_POOL_CTRL_ADDR(UNIT))


/**
 * Write the value of the POOL.CTRL register of one of the POOL units.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'POOL_0'
 * \param[in] DATA is the value that must be written to the register
 */

#define ATON_POOL_CTRL_SET(UNIT, DATA) \
  do { ATON_SET_REG32(ATON_POOL_CTRL_ADDR(UNIT), DATA); } while (0)


/* ------------------------------------------------------------------------------- EN field of the POOL.CTRL register ------------------------------------------------------------------------------- */

/** Size in bits of the EN field of the POOL.CTRL register. */
#define ATON_POOL_CTRL_EN_W  UINT32_C(1)

/** Offset of the EN field of the POOL.CTRL register. */
#define ATON_POOL_CTRL_EN_LSB  UINT32_C(0)


/** Reset value of the EN fields of the POOL.CTRL register. */
#define ATON_POOL_CTRL_EN_DT  UINT8_C(0x0)


/** Mask for retrieving the value of the EN fields of the POOL.CTRL register. */
#define ATON_POOL_CTRL_EN_MASK ATON_FIELD_MASK32(ATON_POOL_CTRL_EN_LSB, ATON_POOL_CTRL_EN_W)



/** If \e true, read accesses to the EN field of the POOL.CTRL register are supported (otherwise reading the field will always return 0). */
#define ATON_POOL_CTRL_EN_AC_R  true

/** If \e true, write accesses to the EN field of the POOL.CTRL register are allowed. */
#define ATON_POOL_CTRL_EN_AC_W  true

/** If \e true, accesses to the EN field of the POOL.CTRL register are secure. */
#define ATON_POOL_CTRL_EN_AC_S  false

/** If \e true, accesses to the EN field of the POOL.CTRL register are privileged. */
#define ATON_POOL_CTRL_EN_AC_P  false


