/* *************************************************************************** VERSION register of one of the POOL units **************************************************************************** */

/** Offset of the POOL.VERSION register from the base address of the POOL unit. */
#define ATON_POOL_VERSION_OFFSET  UINT32_C(0x4)

/**
 * Get the address of the POOL.VERSION register of the POOL unit.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'POOL_0'
 *
 * \return the address of the POOL.VERSION register of POOL unit template
 */

#define ATON_POOL_VERSION_ADDR(UNIT) \
  (ATON_POOL_BASE(UNIT) + ATON_POOL_VERSION_OFFSET)


/**
 * Get the reset value of the POOL.VERSION register of the POOL unit.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'POOL_0'
 *
 * \return the reset value of the POOL.VERSION register of POOL unit template instance having index \e UNIT
 */

#define ATON_POOL_VERSION_DT(UNIT) \
  UINT32_C(0x311c)


/** Read-write access rights mask of the POOL.VERSION register of the POOL unit. */
#define ATON_POOL_VERSION_RW  UINT32_C(0x00000000)

/** Read-only access rights mask of the POOL.VERSION register of the POOL unit. */
#define ATON_POOL_VERSION_RO  UINT32_C(0xffffffff)

/** Write-only access rights mask of the POOL.VERSION register of the POOL unit. */
#define ATON_POOL_VERSION_WO  UINT32_C(0x00000000)


/** Description of the POOL.VERSION register from the base address of the POOL unit. */
#define ATON_POOL_VERSION_DESC  "Version register"


/**
 * Read the value of the POOL.VERSION register of one of the POOL units.
 *
 * \param[in] UNIT is the index of the unit template instance that must be considered:
 *                 - UNIT == 0: 'POOL_0'
 *
 * \return the value of the POOL.VERSION register of POOL unit template instance having index \e UNIT
 */

#define ATON_POOL_VERSION_GET(UNIT) \
  ATON_GET_REG32(ATON_POOL_VERSION_ADDR(UNIT))


/**
 * Ignore a modification of the value of the POOL.VERSION read-only register of one of the POOL units.
 *
 * \param[in] UNIT is ignored
 * \param[in] DATA is ignored
 */

#define ATON_POOL_VERSION_SET(UNIT, DATA) \
  do { ATON_RO_ERROR((const uint8_t *)"POOL.VERSION is a read-only register"); } while (0)


