/**
 * Check if the ISTRS_LOG constant is defined for one of the STRSWITCH units.
 *
 * \param[in] UNIT is the index of the STRSWITCH unit relative to the local constant that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: STRSWITCH_0
 *
 * \retval \e true  if ISTRS_LOG constant is defined for STRSWITCH unit having index \e UNIT
 * \retval \e false otherwise
 */

#define ATON_STRSWITCH_ISTRS_LOG_EXISTS(UNIT) \
  (((UNIT) < 1) ? true : false)


/**
 * Get the value of the ISTRS_LOG constant for one of the STRSWITCH units.
 *
 * \param[in] UNIT is the index of the STRSWITCH unit relative to the local constant whose value must be retrieved;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: STRSWITCH_0
 *
 * \return the value of the ISTRS_LOG constant related to STRSWITCH unit having index \e UNIT
 */

#define ATON_STRSWITCH_ISTRS_LOG(UNIT) \
  (((UNIT) < 1) ? INT64_C(4) : INT64_C(0))


