/**
 * \name Macros of the STRSWITCH units
 */
/*@{*/

/** Number of STRSWITCH unit instances. */
#define ATON_STRSWITCH_NUM 1

/** Size in bytes of the STRSWITCH units. */
#define ATON_STRSWITCH_SIZE  UINT32_C(0x1000)


/**
 * Get the base address of one of the STRSWITCH units.
 *
 * \param[in] UNIT is the index of the STRSWITCH unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: STRSWITCH_0
 *
 * \return the base address of unit having index \e UNIT among the STRSWITCH units
 */

#define ATON_STRSWITCH_BASE(UNIT) \
  (((UNIT) < 1) ? (ATON_BASE + UINT32_C(0x3000)) : 0)


/**
 * Get the pointer to one of the STRSWITCH units.
 *
 * \param[in] UNIT is the index of the STRSWITCH ;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: STRSWITCH_0
 *
 * \return the pointer to unit having index \e UNIT among the STRSWITCH units
 */

#define ATON_STRSWITCH_PTR(UNIT) \
  ((volatile uint32_t *)(intptr_t)ATON_STRSWITCH_BASE(UNIT))


/**
 * Get the identifier of one of the STRSWITCH units.
 *
 * \param[in] UNIT is the index of the STRSWITCH unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: STRSWITCH_0
 *
 * \return the identifier of unit having index \e UNIT among the STRSWITCH units
 */

#define ATON_STRSWITCH_ID(UNIT) \
  ((const volatile uint8_t *)(((UNIT) < 1) ? "STRSWITCH_0" : ""))


/**
 * Get the description of one of the STRSWITCH units.
 *
 * \param[in] UNIT is the index of the STRSWITCH unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: STRSWITCH_0
 *
 * \return the description of unit having index \e UNIT among the STRSWITCH units
 */

#define ATON_STRSWITCH_DESC(UNIT) \
  ((const volatile uint8_t *)(((UNIT) < 1) ? "Stream Switch" : ""))


/** Version of the STRSWITCH units. */
#define ATON_STRSWITCH_VERSION "2.1"


/**
 * Get the IP number of one of the STRSWITCH units.
 *
 * \param[in] UNIT is the index of the STRSWITCH unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: STRSWITCH_0
 *
 * \return the IP number of unit having index \e UNIT among the STRSWITCH units
 */

#define ATON_STRSWITCH_IP_NUMBER(UNIT) \
  ((uint32_t)(((UNIT) < 1) ? 19 : 0))


/**
 * Get the index of the destination Clock Controller unit of one of the CLKA clocks defined by one of the STRSWITCH units.
 * Clock Controller indices are the following:
 * -  0: CLKCTRL_0
 *
 * \param[in] UNIT is the index of the STRSWITCH unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: STRSWITCH_0
 *
 * \return the index of the destination Clock Controller unit of CLKA clock defined by STRSWITCH unit having index \e UNIT
 */

#define ATON_STRSWITCH_CLKA_CLKCTRL(UNIT) \
  (((UNIT) < 1) ? 0 : UINT_MAX)


/**
 * Get the index of CLKA clock in the destination Clock Controller unit.
 *
 * \param[in] UNIT is the index of the STRSWITCH unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: STRSWITCH_0
 *
 * \return the index of CLKA clock in the destination Clock Controller unit considering STRSWITCH unit having index \e UNIT
 */

#define ATON_STRSWITCH_CLKA_CLK(UNIT) \
  (((UNIT) < 1) ? 2 : 0)


/**
 * Return the mask of clock CLKA of one of the STRSWITCH units.
 *
 * \param[in] UNIT    if less than #ATON_STRSWITCH_NUM is the STRSWITCH instance index, otherwise if this value is equal to #ATON_STRSWITCH_NUM it indicates
 *                    that all instances whose CLKA clocks are connected to the same Clock Controller will be considered
 * \param[in] CLKCTRL is the index of the Clock Controller that must be considered:
 *                    -  0: CLKCTRL_0
 * \param[in] REG_IDX is the Clock Controller register index; its value must be less than 1
 *
 * \retval the mask of CLKA clock of a single STRSWITCH instance if \e UNIT is less than #ATON_STRSWITCH_NUM
 * \retval the mask of CLKA clock of all STRSWITCH instances if \e UNIT is equal to #ATON_STRSWITCH_NUM
 * \retval \e 0 if the values of \e UNIT, \e CLKCTRL or \e REG_IDX are not allowed
 */

#define ATON_STRSWITCH_CLK_CLKA_MASK(UNIT, CLKCTRL, REG_IDX) \
  ((((CLKCTRL) == 0) && ((REG_IDX) == 0) && ((UNIT) == 0)) ? UINT32_C(0x4) : \
   (((CLKCTRL) == 0) && ((REG_IDX) == 0) && ((UNIT) == 1)) ? UINT32_C(0x4) : \
   UINT32_C(0x0))



/**
 * Get the number of interrupts used by one of the STRSWITCH units.
 *
 * \param[in] UNIT is the index of the STRSWITCH unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: STRSWITCH_0
 *
 * \return the number of interrupts used by unit having index \e UNIT among the STRSWITCH units.
 */

#define ATON_STRSWITCH_INT_NUM(UNIT) \
  (((UNIT) < 1) ? 1 : 0)


/**
 * Get the index of the destination Interrupt Controller unit of interrupt pin 0 defined by one of the STRSWITCH units.
 * Interrupt Controller indices are the following:
 * -  0: INTCTRL_0
 *
 * \param[in] UNIT is the index of the STRSWITCH unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: STRSWITCH_0
 *
 * \return the index of the destination Interrupt Controller unit of interrupt pin 0 defined by STRSWITCH unit having index \e UNIT
 */

#define ATON_STRSWITCH_INTCTRL(UNIT) \
  (((UNIT) < 1) ? 0 : UINT_MAX)


/** Get the index in the destination Interrupt Controller unit of interrupt pin 0 defined by one of the STRSWITCH units.
 *
 * \param[in] UNIT is the index of the STRSWITCH unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: STRSWITCH_0
 *
 * \return the index in the destination Interrupt Controller unit of interrupt pin 0 defined by STRSWITCH unit having index \e UNIT, or #UINT_MAX if such interrupt pin is not
 *         connected to any Interrupt Controller unit
 */

#define ATON_STRSWITCH_INT(UNIT) \
  (((UNIT) < 1) ? 18 : UINT_MAX)


/**
 * Return the interrupt mask of a STRSWITCH unit.
 *
 * \param[in] UNIT    if less than #ATON_STRSWITCH_NUM is the STRSWITCH instance index, otherwise if this value is equal to #ATON_STRSWITCH_NUM it indicates
 *                    that all instances whose interrupt pins are connected to the same Interrupt Controller will be considered
 * \param[in] INTCTRL is the index of the Interrupt Controller that must be considered:
 *                    -  0: INTCTRL_0
 * \param[in] REG_IDX is the Interrupt Controller register index; its value must be less than 1
 *
 * \retval the interrupt mask of a single STRSWITCH instance if \e UNIT is less than #ATON_STRSWITCH_NUM
 * \retval the interrupt mask of all STRSWITCH instances if \e UNIT is equal to #ATON_STRSWITCH_NUM
 * \retval \e 0 if the values of \e UNIT, \e INTCTRL or \e REG_IDX are not allowed
 */

#define ATON_STRSWITCH_INT_MASK(UNIT, INTCTRL, REG_IDX) \
  ((((INTCTRL) == 0) && ((REG_IDX) == 0) && ((UNIT) == 0)) ? UINT32_C(0x40000) : \
   (((INTCTRL) == 0) && ((REG_IDX) == 0) && ((UNIT) == 1)) ? UINT32_C(0x40000) : \
   UINT32_C(0x0))



/**
 * Return 4 plus the offset of the last register of one of the STRSWITCH units.
 *
 * \param[in] UNIT is the index of the STRSWITCH unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: STRSWITCH_0
 *
 * \return 4 plus the offset of the last register defined by STRSWITCH unit having index \e UNIT
 */

#define ATON_STRSWITCH_LAST_REG_OFFSET(UNIT) \
  (((UNIT) < 1) ? 68 : 0)


/**
 * Check if the register having the given offset exists in one of the STRSWITCH units.
 *
 * \param[in] UNIT   is the index of the STRSWITCH unit that must be considered;
 *                 possible values for \e UNIT are:
 *                 - UNIT == 0: STRSWITCH_0
 * \param[in] OFFSET is the offset of the register that must be considered
 *
 * \retval \e true  if register having offset equal to \e offset exists in STRSWITCH unit having index \e UNIT
 * \retval \e false otherwise
 */

#define ATON_STRSWITCH_REG_OFFSET_EXISTS(UNIT, OFFSET) \
  ((((UNIT) < 1) && (((OFFSET) / 4) < 17)) ? true : false)


