/**
 * Retrieve the UIN (Unique Identification Number) associated with a UIN identifier.
 *
 * \param[in] id is the UIN identifier whose number must be retrieved
 *
 * \return the UIN number associated with UIN identifier \e id, or #UINT32_MAX if such UIN identifier does not exist
 */

#define ATON_ID_TO_UIN(ID) \
  ((strcmp((const char *)ID, "STRSWITCH") == 0) ? ATON_UIN_STRSWITCH : \
   (strcmp((const char *)ID, "STRENG") == 0) ? ATON_UIN_STRENG : \
   (strcmp((const char *)ID, "SENSOR_IF") == 0) ? ATON_UIN_SENSOR_IF : \
   (strcmp((const char *)ID, "VIDEO_OUT") == 0) ? ATON_UIN_VIDEO_OUT : \
   (strcmp((const char *)ID, "IPU_IF") == 0) ? ATON_UIN_IPU_IF : \
   (strcmp((const char *)ID, "ISP_IF") == 0) ? ATON_UIN_ISP_IF : \
   (strcmp((const char *)ID, "MORPH") == 0) ? ATON_UIN_MORPH : \
   (strcmp((const char *)ID, "BACKREMOVE") == 0) ? ATON_UIN_BACKREMOVE : \
   (strcmp((const char *)ID, "REFUPDATE") == 0) ? ATON_UIN_REFUPDATE : \
   (strcmp((const char *)ID, "CONV") == 0) ? ATON_UIN_CONV : \
   (strcmp((const char *)ID, "CROP") == 0) ? ATON_UIN_CROP : \
   (strcmp((const char *)ID, "CORNER_DETECT") == 0) ? ATON_UIN_CORNER_DETECT : \
   (strcmp((const char *)ID, "CENSUS") == 0) ? ATON_UIN_CENSUS : \
   (strcmp((const char *)ID, "RECT") == 0) ? ATON_UIN_RECT : \
   (strcmp((const char *)ID, "JPEG_ENC") == 0) ? ATON_UIN_JPEG_ENC : \
   (strcmp((const char *)ID, "JPEG_DEC") == 0) ? ATON_UIN_JPEG_DEC : \
   (strcmp((const char *)ID, "DEBUG_CTRL") == 0) ? ATON_UIN_DEBUG_CTRL : \
   (strcmp((const char *)ID, "GP_CTRL") == 0) ? ATON_UIN_GP_CTRL : \
   (strcmp((const char *)ID, "SBDOG") == 0) ? ATON_UIN_SBDOG : \
