/** CLKCTRL_0 (Clock Controller). */
#define ATON_IP_CLKCTRL_0 16

/** INTCTRL_0 (Interrupt Controller). */
#define ATON_IP_INTCTRL_0 17

/** BUSIF_0 (Bus Interface 0). */
#define ATON_IP_BUSIF_0 18

/** STRSWITCH_0 (Stream Switch). */
#define ATON_IP_STRSWITCH_0 19

/** STRENG_0 (Stream Engine 0). */
#define ATON_IP_STRENG_0 0

/** STRENG_1 (Stream Engine 1). */
#define ATON_IP_STRENG_1 1

/** STRENG_2 (Stream Engine 2). */
#define ATON_IP_STRENG_2 2

/** STRENG_3 (Stream Engine 3). */
#define ATON_IP_STRENG_3 3

/** STRENG_4 (Stream Engine 4). */
#define ATON_IP_STRENG_4 4

/** STRENG_5 (Stream Engine 5). */
#define ATON_IP_STRENG_5 5

/** CONVACC_0 (Convolutional Accelerator 0). */
#define ATON_IP_CONVACC_0 6

/** ACTIV_0 (Activation Accelerator 0). */
#define ATON_IP_ACTIV_0 7

/** ARITH_0 (Arithmetic Accelerator 0). */
#define ATON_IP_ARITH_0 8

/** ARITH_1 (Arithmetic Accelerator 1). */
#define ATON_IP_ARITH_1 9

/** POOL_0 (Pooling Accelerator 0). */
#define ATON_IP_POOL_0 10

/** EPOCHCTRL_0 (Epoch Controller 0). */
#define ATON_IP_EPOCHCTRL_0 11

/** DEBUG_TRACE_0 (Debug Trace 0). */
#define ATON_IP_DEBUG_TRACE_0 12



