/**
 * Return the IP number of the Stream Switch having this unit as destination unit.
 *
 * \param[in] ip   is the IP number of the destination unit (\e ip < 11)
 * \param[in] pidx is the index of the physical input port of the destination unit (\e pidx < 3)
 * \param[in] vidx is the index of the physical input channel of the destination unit (\e vidx < 1)
 *
 * \return the IP number of the Stream Switch having this unit as destination unit given the values of \e ip, \e pidx and \e vidx input arguments, or -1 if the values of the input arguments are not valid
 */

#define ATON_STRSWITCH_DST_REG_IP(IP, PIDX, VIDX) \
  ((((IP == 0) && (PIDX == 0) && (VIDX == 0)) || \
    ((IP == 1) && (PIDX == 0) && (VIDX == 0)) || \
    ((IP == 2) && (PIDX == 0) && (VIDX == 0)) || \
    ((IP == 3) && (PIDX == 0) && (VIDX == 0)) || \
    ((IP == 4) && (PIDX == 0) && (VIDX == 0)) || \
    ((IP == 5) && (PIDX == 0) && (VIDX == 0)) || \
    ((IP == 6) && (PIDX == 0) && (VIDX == 0)) || \
    ((IP == 6) && (PIDX == 1) && (VIDX == 0)) || \
    ((IP == 6) && (PIDX == 2) && (VIDX == 0)) || \
    ((IP == 7) && (PIDX == 0) && (VIDX == 0)) || \
    ((IP == 8) && (PIDX == 0) && (VIDX == 0)) || \
    ((IP == 8) && (PIDX == 1) && (VIDX == 0)) || \
    ((IP == 9) && (PIDX == 0) && (VIDX == 0)) || \
    ((IP == 9) && (PIDX == 1) && (VIDX == 0)) || \
    ((IP == 10) && (PIDX == 0) && (VIDX == 0))) ? 19 : \
   -1)


