/**
 * Retrieve the IP number of the Clock Controller connected to CLKA clock of a unit.
 *
 * \param[in] src_unit is the IP number of the unit whose CLKA clock is being considered
 * \param[in] dst_plug if not \e NULL, is the pointer to the memory location that will contain the index of the CLKA clock plug of the Clock Controller
 *                     connected to unit having IP number equal to \e src_unit
 *
 * \return the IP number of the Clock Controller connected to CLKA clock of unit having IP number equal to \e src_unit, or #UINT32_MAX if no such
 *         connection exists
 */

static inline uint32_t ATON_GET_CLKA_CLKCTRL_CONNECTED_TO_UNIT(uint32_t src_unit, uint32_t *dst_plug)
{
  uint32_t tmp_dst_clkc = UINT32_MAX,
           tmp_dst_plug = UINT32_MAX;

  switch (src_unit)
  {
    case ATON_IP_INTCTRL_0:
    {
      tmp_dst_clkc = ATON_IP_CLKCTRL_0;
      tmp_dst_plug = 0;

      break;
    }

    case ATON_IP_BUSIF_0:
    {
      tmp_dst_clkc = ATON_IP_CLKCTRL_0;
      tmp_dst_plug = 1;

      break;
    }

    case ATON_IP_STRSWITCH_0:
    {
      tmp_dst_clkc = ATON_IP_CLKCTRL_0;
      tmp_dst_plug = 2;

      break;
    }
  }

  if ((tmp_dst_clkc != UINT32_MAX) && (dst_plug != NULL))
    *dst_plug = tmp_dst_plug;

  return tmp_dst_clkc;
}


